// Filter Upcoming Appointments
// Keeps only appointments scheduled for today or tomorrow
// with status Pending or Confirmed (not already Cancelled)

const allRows = $input.all();
const now = new Date();
const todayStr = now.toISOString().split('T')[0];

const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];

const upcoming = allRows.filter(r => {
  const apptDate = (r.json.appointmentDate || '').split('T')[0];
  const status = (r.json.status || '').toLowerCase();
  return (
    (apptDate === todayStr || apptDate === tomorrowStr) &&
    (status === 'pending' || status === 'confirmed')
  );
});

if (upcoming.length === 0) {
  return [{ json: { message: 'No upcoming appointments to remind', count: 0 } }];
}

// Return each appointment as a separate item for the loop
return upcoming.map(r => ({ json: r.json }));

// Build Personalised Reminder Message
// Creates a WhatsApp reminder with appointment details
// and action options for the patient

const appt = $json;

const patientName = $('Google Sheets – Read Appointments').first().json.patientName|| 'Patient';
const phone =  $('Google Sheets – Read Appointments').first().json.phone|| '';
const doctorName = $('Google Sheets – Read Appointments').first().json.doctorName || 'your doctor';
const appointmentDate = $('Google Sheets – Read Appointments').first().json.appointmentDate || '';
const appointmentTime = $('Google Sheets – Read Appointments').first().json.appointmentTime || '';
const clinicName = $('Google Sheets – Read Appointments').first().json.clinicName || 'our clinic';
const appointmentId =  $('Google Sheets – Read Appointments').first().json.appointmentId|| appt.rowIndex || '';
const speciality = $('Google Sheets – Read Appointments').first().json.speciality || '';

// Format date nicely
let formattedDate = appointmentDate;
try {
  const d = new Date(appointmentDate);
  formattedDate = d.toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
} catch(e) {}

const isToday = appointmentDate.split('T')[0] === new Date().toISOString().split('T')[0];
const urgency = isToday ? '🔴 *TODAY*' : '📅 *TOMORROW*';

const lines = [
  `👋 Hello *${patientName}!*`,
  '',
  `⏰ *Appointment Reminder* ${urgency}`,
  '',
  `🏥 *Clinic:* ${clinicName}`,
  `👨‍⚕️ *Doctor:* ${doctorName}${speciality ? ` (${speciality})` : ''}`,
  `📅 *Date:* ${formattedDate}`,
  `🕐 *Time:* ${appointmentTime}`,
  '',
  '━━━━━━━━━━━━━━━━━━',
  'Please reply with one of:',
  '',
  '✅ *confirm* – I will be there',
  '🔁 *reschedule* – I need another time',
  '❌ *cancel* – I need to cancel',
  '',
  'Reply *myappointment* to see full details.'
];

return {
  json: {
    phone,
    patientName,
    appointmentId,
    reminderMessage: lines.join('\n')
  }
};

// Find & Confirm Appointment
// Finds the next upcoming appointment for this phone number
// Returns appointment details + confirmation message

const phone =$input.first().json.phone;
const patientName = $input.first().json.patientName || 'Patient';
const allRows = $input.all();
const now = new Date();

// Find the soonest upcoming appointment for this phone
const myAppts = allRows
  .filter(r => r.json.phone === phone && ['pending','confirmed'].includes((r.json.status||'').toLowerCase()))
  .sort((a, b) => new Date(a.json.appointmentDate) - new Date(b.json.appointmentDate));

if (myAppts.length === 0) {
  return [{ json: {
    phone,
    confirmMessage: `⚠️ *No upcoming appointment found.*\n\nReply *myappointment* to check your bookings.`,
    hasAppointment: false
  }}];
}

const appt = myAppts[0].json;
let formattedDate = appt.appointmentDate;
try {
  formattedDate = new Date(appt.appointmentDate).toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
} catch(e) {}

const confirmLines = [
  `✅ *Appointment Confirmed!*`,
  '',
  `Thank you, *${patientName}!* We have noted your confirmation.`,
  '',
  `🏥 *Clinic:* ${appt.clinicName || 'Our Clinic'}`,
  `👨‍⚕️ *Doctor:* ${appt.doctorName || 'Your Doctor'}`,
  `📅 *Date:* ${formattedDate}`,
  `🕐 *Time:* ${appt.appointmentTime}`,
  '',
  '📍 Please arrive 10 minutes early.',
  '📄 Bring any previous reports or prescriptions.',
  '',
  'See you soon! 😊'
];

return [{ json: {
  phone,
  appointmentId: appt.appointmentId || appt.rowIndex,
  calendarEventId: appt.calendarEventId || '',
  confirmMessage: confirmLines.join('\n'),
  hasAppointment: true,
  appointmentDate: appt.appointmentDate,
  appointmentTime: appt.appointmentTime,
  doctorName: appt.doctorName,
  patientName
}}];

// Process Cancellation
// Finds appointment, builds cancel + admin notification messages

const phone =  $input.first().json.phone|| $('WATI Trigger').item.json.from;
const patientName = $input.first().json.patientName || 'Patient';
const allRows = $input.all();

const myAppts = allRows
  .filter(r => r.json.phone === phone && ['pending','confirmed'].includes((r.json.status||'').toLowerCase()))
  .sort((a, b) => new Date(a.json.appointmentDate) - new Date(b.json.appointmentDate));

if (myAppts.length === 0) {
  return [{ json: {
    phone,
    cancelMessage: `⚠️ *No upcoming appointment found to cancel.*`,
    adminMessage: '',
    hasAppointment: false
  }}];
}

const appt = myAppts[0].json;
let formattedDate = appt.appointmentDate;
try {
  formattedDate = new Date(appt.appointmentDate).toLocaleDateString('en-IN', { weekday: 'long', month: 'long', day: 'numeric' });
} catch(e) {}

const cancelLines = [
  `❌ *Appointment Cancelled*`,
  '',
  `We have cancelled your appointment, *${patientName}.*`,
  '',
  `🗑️ *Cancelled:* ${appt.doctorName || 'Doctor'} on ${formattedDate} at ${appt.appointmentTime}`,
  '',
  'If you wish to rebook, send *courses* or contact us directly.',
  'We hope to see you again soon! 🙏'
];

const adminLines = [
  `🚨 *Appointment Cancelled*`,
  '',
  `👤 *Patient:* ${patientName}`,
  `📞 *Phone:* ${phone}`,
  `👨‍⚕️ *Doctor:* ${appt.doctorName || 'N/A'}`,
  `📅 *Date:* ${formattedDate}`,
  `🕐 *Time:* ${appt.appointmentTime}`,
  '',
  'Slot is now available for rebooking.'
];

return [{ json: {
  phone,
  patientName,
  appointmentId: appt.appointmentId || '',
  calendarEventId: appt.calendarEventId || '',
  cancelMessage: cancelLines.join('\n'),
  adminMessage: adminLines.join('\n'),
  hasAppointment: True
}}];

// Build Available Slots Message
// Reads AvailableSlots sheet, filters out booked slots
// Sends a numbered list to the patient

const phone = $('Wati Trigger').first().json.waId || $('WATI Trigger').item.json.from;
const patientName =  $('Wati Trigger').first().json.senderName|| 'Patient';
const allSlots = $input.all();

// Filter only available (not booked) slots in the future
const now = new Date();
const availableSlots = allSlots.filter(r => {
  const slotDate = new Date(`${r.json.date} ${r.json.time}`);
  return (r.json.status || '').toLowerCase() === 'available' && slotDate > now;
}).slice(0, 8); // show max 8 slots

if (availableSlots.length === 0) {
  return [{ json: {
    phone,
    slotsMessage: `⚠️ *No available slots right now.*\n\nPlease call us directly to reschedule.\n📞 Contact: YOUR_CLINIC_PHONE`,
    slots: []
  }}];
}

const lines = [
  `🔁 *Reschedule Appointment*`,
  `Hi *${patientName}*, here are the available slots:`,
  ''
];

const slotsData = [];
for (let i = 0; i < availableSlots.length; i++) {
  const s = availableSlots[i].json;
  let formattedDate = s.date;
  try {
    formattedDate = new Date(s.date).toLocaleDateString('en-IN', { weekday: 'short', month: 'short', day: 'numeric' });
  } catch(e) {}
  lines.push(`*${i + 1}.* 📅 ${formattedDate} at 🕐 ${s.time} — Dr. ${s.doctorName || 'Available'}`);
  slotsData.push({ index: i + 1, date: s.date, time: s.time, doctorName: s.doctorName, slotId: s.slotId || `${s.date}_${s.time}` });
}

lines.push('');
lines.push('Reply *slot <number>* to confirm.');
lines.push('Example: *slot 2*');

// Store slots data as JSON string for next step
return [{ json: {
  phone,
  patientName,
  slotsMessage: lines.join('\n'),
  slotsData: JSON.stringify(slotsData)
}}];

// Process Slot Selection
// Input: 'slot 2'
// Reads saved session, finds the slot, updates appointment

const text = ($('WATI Trigger').item.json.text || '').trim();
const phone = $('WATI Trigger').item.json.waId || $('WATI Trigger').item.json.from;
const patientName = $('WATI Trigger').item.json.senderName || 'Patient';

// Parse slot number
const slotNum = parseInt(text.replace(/^slot\s+/i, '').trim());
if (isNaN(slotNum) || slotNum < 1) {
  return [{ json: {
    phone,
    slotMessage: `⚠️ Invalid slot number. Reply *reschedule* to see available slots again.`,
    success: False
  }}];
}

// Find the most recent session for this phone
const allSessions = $input.all();
const mySessions = allSessions
  .filter(r => r.json.phone === phone)
  .sort((a, b) => new Date(b.json.createdAt) - new Date(a.json.createdAt));

if (mySessions.length === 0) {
  return [{ json: {
    phone,
    slotMessage: `⚠️ No active reschedule session found.\nSend *reschedule* to start again.`,
    success: False
  }}];
}

let slots = [];
try {
  slots = JSON.parse(mySessions[0].json.slotsData || '[]');
} catch(e) { slots = []; }

const selected = slots.find(s => s.index === slotNum);
if (!selected) {
  return [{ json: {
    phone,
    slotMessage: `⚠️ Slot *${slotNum}* not found. Send *reschedule* to see the list again.`,
    success: False
  }}];
}

let formattedDate = selected.date;
try {
  formattedDate = new Date(selected.date).toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
} catch(e) {}

const confirmLines = [
  `✅ *Appointment Rescheduled!*`,
  '',
  `Great choice, *${patientName}!* Your appointment has been updated.`,
  '',
  `👨‍⚕️ *Doctor:* Dr. ${selected.doctorName || 'Available'}`,
  `📅 *New Date:* ${formattedDate}`,
  `🕐 *New Time:* ${selected.time}`,
  '',
  '📍 Please arrive 10 minutes early.',
  'Reply *myappointment* to verify your booking.',
  '',
  'See you soon! 😊'
];

const adminLines = [
  `🔁 *Appointment Rescheduled*`,
  `👤 *Patient:* ${patientName}`,
  `📞 *Phone:* ${phone}`,
  `📅 *New Date:* ${formattedDate}`,
  `🕐 *New Time:* ${selected.time}`,
  `👨‍⚕️ *Doctor:* Dr. ${selected.doctorName || 'N/A'}`
];

return [{ json: {
  phone, patientName,
  newDate: selected.date,
  newTime: selected.time,
  newDoctorName: selected.doctorName,
  slotId: selected.slotId,
  slotMessage: confirmLines.join('\n'),
  adminMessage: adminLines.join('\n'),
  success: True
}}];

// Build My Appointment Status Card
// Shows patient's current and past appointments

const phone =  $input.first().json.phone|| $('WATI Trigger').item.json.from;
const patientName =  $input.first().json.patientName|| 'Patient';
const allRows = $input.all();

const myAppts = allRows
  .filter(r => r.json.phone === phone)
  .sort((a, b) => new Date(b.json.appointmentDate) - new Date(a.json.appointmentDate));

if (myAppts.length === 0) {
  return [{ json: {
    phone,
    myApptMessage: `📋 *No appointments found, ${patientName}!*\n\nPlease contact us to book an appointment.`
  }}];
}

const upcoming = myAppts.filter(r => ['pending','confirmed','rescheduled'].includes((r.json.status||'').toLowerCase()));
const past = myAppts.filter(r => ['cancelled','completed'].includes((r.json.status||'').toLowerCase())).slice(0, 3);

const lines = [`📋 *My Appointments*`, `👤 *${patientName}*`, ''];

const statusEmoji = { confirmed: '✅', pending: '⏳', rescheduled: '🔁', cancelled: '❌', completed: '🏁' };

if (upcoming.length > 0) {
  lines.push('*Upcoming:*');
  for (const r of upcoming) {
    let fd = r.json.appointmentDate;
    try { fd = new Date(r.json.appointmentDate).toLocaleDateString('en-IN', { weekday: 'short', month: 'short', day: 'numeric' }); } catch(e) {}
    const emoji = statusEmoji[(r.json.status||'').toLowerCase()] || '📅';
    lines.push(`${emoji} *${fd}* at ${r.json.appointmentTime}`);
    lines.push(`   Dr. ${r.json.doctorName || 'N/A'} | ${r.json.clinicName || 'Clinic'}`);
    lines.push(`   Status: ${r.json.status}`);
    lines.push('');
  }
}

if (past.length > 0) {
  lines.push('*Recent History:*');
  for (const r of past) {
    let fd = r.json.appointmentDate;
    try { fd = new Date(r.json.appointmentDate).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' }); } catch(e) {}
    const emoji = statusEmoji[(r.json.status||'').toLowerCase()] || '📅';
    lines.push(`${emoji} ${fd} – Dr. ${r.json.doctorName || 'N/A'} (${r.json.status})`);
  }
  lines.push('');
}

lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('Reply *confirm*, *reschedule* or *cancel* to manage your appointment.');

return [{ json: { phone, myApptMessage: lines.join('\n') } }];
